import { readFile, writeFile } from "node:fs/promises";

const read = (file) => readFile(new URL(file, import.meta.url), "utf8");

const data = (await read("data.js")).replace(/^export\s+/gm, "");
const engine = (await read("engine.js"))
  .replace(/^import\s*\{[\s\S]*?\}\s*from\s*"\.\/data\.js";\s*/m, "")
  .replace(/^export\s+/gm, "");
const app = (await read("app.js"))
  .replace(/^import\s*\{[\s\S]*?\}\s*from\s*"\.\/data\.js";\s*/m, "")
  .replace(/^import\s*\{[\s\S]*?\}\s*from\s*"\.\/engine\.js";\s*/m, "");

const bundle = `/* Generated by build-bundle.mjs. Do not edit directly. */\n\n${data}\n\n${engine}\n\n${app}`;

if (/^\s*(import|export)\s/m.test(bundle)) {
  throw new Error("O bundle ainda contém sintaxe de módulo.");
}

await writeFile(new URL("script.js", import.meta.url), bundle, "utf8");
